void
print_token(const antlr4::Token* token,
            const std::vector<LineInfo>& lineInfo,
            std::ofstream& outFile,
            const antlr4::Lexer& lexer,
            const std::string& input)
{
  auto& vocabulary = lexer.getVocabulary();

  std::string tokenTypeName =
    std::string(vocabulary.getSymbolicName(token->getType()));

  if (tokenTypeName.empty())
    tokenTypeName = "<UNKNOWN>";

  auto it = tokenTypeMapping.find(tokenTypeName);
  if (it != tokenTypeMapping.end()) {
    tokenTypeName = it->second;
  }

  size_t antlrLine = token->getLine();
  size_t antlrCol = token->getCharPositionInLine();

  // Build location info
  std::string locInfo;
  if (antlrLine > 0 && antlrLine <= lineInfo.size()) {
    const auto& info = lineInfo[antlrLine - 1];
    locInfo = " Loc=<" + info.filename + ":" +
              std::to_string(info.sourceLine) + ":" +
              std::to_string(antlrCol + 1) + ">";
  } else if (tokenTypeName == "eof" && !lineInfo.empty()) {
    // EOF: use last line info but column + 1
    const auto& info = lineInfo.back();
    locInfo = " Loc=<" + info.filename + ":" +
              std::to_string(info.sourceLine) + ":" +
              std::to_string(antlrCol + 1) + ">";
  } else {
    locInfo = " Loc=<0:0>";
  }

  // Detect StartOfLine and LeadingSpace
  // Use the raw input to check what's before this token
  bool startOfLine = false;
  bool leadingSpace = false;

  if (tokenTypeName != "eof") {
    size_t startIdx = token->getStartIndex();
    // Scan backwards from token start to find the beginning of the line
    size_t lineStart = startIdx;
    while (lineStart > 0 && input[lineStart - 1] != '\n') {
      lineStart--;
    }
    // Check if token is at the very start of the line (no non-whitespace before it)
    // OR if there's a space/tab before the token on the same line
    std::string beforeToken = input.substr(lineStart, startIdx - lineStart);
    if (beforeToken.empty() || beforeToken.find_first_not_of(" \t") == std::string::npos) {
      if (beforeToken.empty()) {
        startOfLine = true;
      } else {
        // Only whitespace before token - it could be StartOfLine or LeadingSpace
        startOfLine = true; // Token is first non-whitespace on the line
        if (!beforeToken.empty()) {
          leadingSpace = true; // There is whitespace before it
        }
      }
    } else {
      // There's some non-whitespace before token on the same line
      // Check if there's whitespace immediately before the token
      size_t lastNonWs = beforeToken.find_last_not_of(" \t");
      if (lastNonWs != std::string::npos) {
        size_t afterLastNonWs = lastNonWs + 1;
        if (afterLastNonWs < beforeToken.length()) {
          leadingSpace = true;
        }
      }
    }
  }

  // Print token
  if (tokenTypeName != "eof") {
    outFile << tokenTypeName << " '" << token->getText() << "'";
  } else {
    outFile << tokenTypeName << " ''";
  }

  if (startOfLine)
    outFile << "\t [StartOfLine]";
  if (leadingSpace)
    outFile << " [LeadingSpace]";
  outFile << "\t" << locInfo << std::endl;
}

int
main(int argc, char* argv[])
{
  if (argc != 3) {
    std::cout << "Usage: " << argv[0] << " <input> <output>\n";
    return -1;
  }

  std::ifstream inFile(argv[1]);
  if (!inFile) {
    std::cout << "Error: unable to open input file: " << argv[1] << '\n] << '\n';
    return -2;
  }

  std::ofstream outFile(argv[2]);
  if (!outFile) {
    std::cout << "Error: unable to open output file: " << argv[2] << '\n';
    return -3;
  }

  std::cout << "程序 '" << argv[0] << std::endl;
  std::cout << "输入 '" << argv[1] << std::endl;
  std::cout << "输出 '" << argv[2] << std::endl;

  // Read entire input
  std::stringstream buffer;
  buffer << inFile.rdbuf();
  std::string content = buffer.str();

  // Preprocess: parse line markers and build mapping
  auto [lineInfo, cleanContent] = preprocess(content);

  // Feed clean content to ANTLR
  antlr4::ANTLRInputStream input(cleanContent);
  SYsULexer lexer(&input);

  antlr4::CommonTokenStream tokens(&lexer);
  tokens.fill();

  for (auto&& token : tokens.getTokens()) {
    print_token(token, lineInfo, outFile, lexer, cleanContent);
  }
}

